{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🔹 Определение"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"store.subscribe(listener)"},{"type":"text","text":" — это метод Redux-хранилища ("},{"type":"text","marks":[{"type":"bold"}],"text":"store"},{"type":"text","text":"),"},{"type":"hardBreak"},{"type":"text","text":"который позволяет "},{"type":"text","marks":[{"type":"bold"}],"text":"подписаться на изменения состояния"},{"type":"text","text":"."}]},{"type":"blockquote","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"То есть: каждый раз, когда состояние ("},{"type":"text","marks":[{"type":"code"}],"text":"state"},{"type":"text","text":") изменяется — вызывается ваша функция-слушатель ("},{"type":"text","marks":[{"type":"code"}],"text":"listener"},{"type":"text","text":")."}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🔹 Простыми словами"}]},{"type":"blockquote","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"subscribe()"},{"type":"text","text":" позволяет “следить” за изменениями состояния в store."},{"type":"hardBreak"},{"type":"text","text":"Когда кто-то вызвал "},{"type":"text","marks":[{"type":"code"}],"text":"dispatch()"},{"type":"text","text":", и reducer вернул новое состояние — все подписчики получают уведомление."}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🔹 Пример"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import { createStore } from 'redux'

// Reducer
function counterReducer(state = { count: 0 }, action) {
  switch (action.type) {
    case 'INCREMENT':
      return { count: state.count + 1 }
    default:
      return state
  }
}

// Создаём store
const store = createStore(counterReducer)

// Подписываемся на обновления
const unsubscribe = store.subscribe(() => {
  console.log('State изменился:', store.getState())
})

// Отправляем action
store.dispatch({ type: 'INCREMENT' })
// → "State изменился: { count: 1 }"

