// Reducer для задач
function todosReducer(state = [], action) {
  switch (action.type) {
    case 'ADD_TODO':
      return [...state, action.payload]
    default:
      return state
  }
}

// Reducer для пользователя
function userReducer(state = { name: '' }, action) {
  switch (action.type) {
    case 'SET_USER':
      return { ...state, name: action.payload }
    default:
      return state
  }
}

// Объединяем редьюсеры
const rootReducer = combineReducers({
  todos: todosReducer,
  user: userReducer,
})

// Создаём store
const store = createStore(rootReducer)
